INSERT INTO public.training_videos (url, title, description, category, status) VALUES
('https://www.youtube.com/watch?v=e7C-DgSmo-g', '수면을 미끄러져 가는 자유형 베이스 스트로크', '한다경 선수의 자유형 베이스 드릴 영상으로, 부드럽고 효율적인 스트로크 감각을 익히기 좋음.', '훈련 영상', 'approved'),
('https://www.youtube.com/watch?v=_s6QIe7gr9k', '빠른 자유형을 위한 전신감각 스피드 훈련', '자유형 스피드를 높이기 위한 전신 연결과 감각 훈련을 배울 수 있음.', '훈련 영상', 'approved'),
('https://www.youtube.com/watch?v=jL_B6Mk1nfk', '자유형의 모든 것 [KNSU 스포츠클럽]', '한국체육대학교 기반 콘텐츠로 자유형 핵심 기술을 폭넓게 정리하기 좋음.', '훈련 영상', 'approved'),
('https://www.youtube.com/watch?v=Cv1_G1niINA', '왕초보 수영배우기 3화 - 자유형 발차기', '선수들도 기본을 다시 점검하기 좋은 자유형 킥 기본 영상.', '훈련 영상', 'approved'),
('https://www.youtube.com/watch?v=knmcy8iRQqo', '왕초보 수영배우기 4화 - 손돌리기와 호흡', '자유형 팔돌리기와 호흡 타이밍을 기초부터 다시 확인할 수 있음.', '훈련 영상', 'approved'),
('https://www.youtube.com/watch?v=6kley6CTrAQ', '자유형 플립턴 마스터하기', '자유형 경기에서 기록 단축에 중요한 플립턴을 단계적으로 익히기 좋음.', '훈련 영상', 'approved'),
('https://www.youtube.com/watch?v=Vv6BO44Euac', '오픈턴 마스터하기', '평영과 접영에서 사용하는 오픈턴을 정리한 영상으로, 터치 후 전환 동작 점검에 좋음.', '훈련 영상', 'approved'),
('https://www.youtube.com/watch?v=balI6kn6Q5I', '배영 롤 오버 턴 마스터하기', '배영 턴을 더 빠르고 정확하게 만들고 싶은 선수들에게 추천.', '훈련 영상', 'approved'),
('https://www.youtube.com/watch?v=2_z4QRS60Og', '플립턴 강좌: 단 한 번의 성공', '플립턴을 어려워하는 선수들이 회전 감각을 잡기 좋음.', '훈련 영상', 'approved'),
('https://www.youtube.com/watch?v=RHuYnzLbC0I', '수영레슨 비법전수 84편 - 그랩 스타트 기본편', '국가대표 출신 코치가 알려주는 그랩 스타트 기본 영상.', '훈련 영상', 'approved'),
('https://www.youtube.com/watch?v=hq_MgXcqQSo', '수영레슨 비법전수 87편 - 릴레이스타트', '계영 인계와 릴레이 스타트 감각을 익히기 좋은 영상.', '훈련 영상', 'approved'),
('https://www.youtube.com/watch?v=0VgIaUOWrdY', '수영레슨 비법전수 3편 - 유선형', '스타트와 턴 이후 기록을 좌우하는 유선형 자세를 점검할 수 있음.', '훈련 영상', 'approved'),
('https://www.youtube.com/watch?v=Fg3O7SvvrPQ', '수영레슨 비법전수 83편 - 배영 백돌핀킥', '배영 스타트와 턴 이후 잠영 구간을 강화하는 데 도움 됨.', '훈련 영상', 'approved'),
('https://www.youtube.com/watch?v=Wu6f0owRlq8', '수영레슨 비법전수 81편 - 배영 헤드업드릴', '배영 자세 안정과 머리 위치 조절을 연습하기 좋음.', '훈련 영상', 'approved'),
('https://www.youtube.com/watch?v=ObuTMv4rqQs', '수영레슨 비법전수 16편 - 자유형 풀동작훈련법 1', '자유형 팔로 물을 잡고 밀어내는 풀 동작을 교정하기 좋음.', '훈련 영상', 'approved'),
('https://www.youtube.com/watch?v=o0p42PmHo2E', '국가대표 박한별의 배영 잘하는 팁 - 배영스트록', '배영 스트로크와 몸의 균형을 국가대표 시범으로 볼 수 있음.', '훈련 영상', 'approved'),
('https://www.youtube.com/watch?v=lrEDVVuAp2U', '박한별 선수의 수영 전 지상훈련 루틴 20분', '수영 전 몸을 깨우는 지상훈련 루틴으로 훈련 전 준비운동 자료로 좋음.', '기타 수영 관련', 'approved'),
('https://www.youtube.com/watch?v=hp9gBbjBhTI', '수영 여신 박한별이 직접 알려주는 돌핀킥 레슨', '모든 영법에 도움이 되는 돌핀킥 감각을 배울 수 있음.', '훈련 영상', 'approved'),
('https://www.youtube.com/watch?v=kg0UE-n9wv0', '수준 단계별 적절한 드릴 동작은? 다양한 배영 드릴 훈련 지도법', '배영 수준별 드릴을 확인할 수 있어 선수별 맞춤 훈련에 활용 가능.', '훈련 영상', 'approved'),
('https://www.youtube.com/watch?v=VJkjFMkO5Tg', '끊기지 않는 배영 하는 방법 - 배영콤비훈련', '배영 팔동작과 킥 연결이 끊기는 선수에게 도움 됨.', '수영 상식', 'approved'),
('https://www.youtube.com/watch?v=wrcKIOgqrJE', '배영 드릴 - 다운스위프, 몸통 골반 롤링, 사이드 킥 롤링', '배영 롤링과 킥의 연결 감각을 익히는 드릴 영상.', '훈련 영상', 'approved'),
('https://www.youtube.com/watch?v=QU7K07xLA9Y', 'Backstroke Movement - Stroke, Kick, Turn / 배영선수 함찬미', '배영 스트로크, 킥, 턴을 선수 움직임으로 관찰하기 좋음.', '훈련 영상', 'approved'),
('https://www.youtube.com/watch?v=YdOM8GkWFk0', '평영 손 배우기 18년차 수영샘의 노하우', '평영 손동작과 머리 타이밍을 세밀하게 점검하기 좋음.', '수영 상식', 'approved'),
('https://www.youtube.com/watch?v=MwLFTjldakE', 'Breaststroke Movement - 깔끔한 평영 움직임과 타이밍 살펴보기', '평영 리듬, 글라이드, 킥 타이밍을 관찰하기 좋은 영상.', '훈련 영상', 'approved'),
('https://www.youtube.com/watch?v=QhFPJp5P8FE', '상하체 분리 컨트롤과 평영 글라이드', '평영에서 상체와 하체 타이밍이 맞지 않는 선수에게 추천.', '훈련 영상', 'approved'),
('https://www.youtube.com/watch?v=4VV7rpcBSWA', '평영특강 3탄 - 앞으로 나아가는 평영, 상체에 달렸다', '평영 추진력이 약한 선수들이 상체 활용을 이해하기 좋음.', '훈련 영상', 'approved'),
('https://www.youtube.com/watch?v=IHGmwx5zW_A', '평영 교과서대로 하면 망합니다', '평영 글라이드와 웨이브 감각을 현실적으로 점검할 수 있음.', '훈련 영상', 'approved'),
